---@class LServerListGetter
local LServerListGetter = LxClass("LServerListGetter", nil)

function LServerListGetter:LServerListGetter()
	self._gameServerData = nil
	self._resultCb = nil
end

function LServerListGetter:Dispose()
	if self._isDisposed then return end
	table.removeall(self)
	self._isDisposed = true
end

function LServerListGetter:SetResultCallback(resultCb)
	self._resultCb = resultCb
end

function LServerListGetter:StartQueryState(serverId)
	if self._isQuerying then return end
	self._isQuerying = true
	LServerUtil.QueryServerListWithStateFromWeb(function(bOk, ret,result,url)
		if self._isDisposed then return end
		self._isQuerying = false
		local cb = self._resultCb
		if cb ~= nil then
			cb(bOk, ret, result, nil)
		end
	end, serverId)
end

function LServerListGetter:StartQueryAll()
	if self._isQuerying then return end

	self._isQuerying = true
	self._finishedCount = 0
	self._isError = false
	self._errorCode = 0
	self._errorResult = nil

	LServerUtil.QueryServerListFromWeb(function(...)
		if self._isDisposed then return end
		self:OnGameServerDataCallback(...)
	end)
end

function LServerListGetter:CheckFinished()
	if self._finishedCount < 1 then return end
	self._isQuerying = false
	local cb = self._resultCb
	if cb ~= nil then
		if not self._isError then
			cb(true, 0, self._gameServerData)
		else
			cb(true, self._errorCode, self._errorResult, nil)
		end
	end
end


function LServerListGetter:OnGameServerDataCallback(bOk, ret,result,url)
	self._finishedCount = self._finishedCount + 1
	if not bOk or not result then
		self._isError = true
		self._errorCode = ret
		self._gameServerData = nil
		self._errorResult = result
	else
		self._gameServerData = result
	end
	self:CheckFinished()
end


