function LServerUtil._QueryUpdateConfigFromWeb(callFunc, qType, gid, sid)
	local urlSuffix = ""
	local urlList = LGameSettings.updateUrlList
	local packageId = "0"
	packageId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or packageId
	if tonumber(packageId) == 0 then
		packageId = LGameSettings.platformId or packageId
	end

	local time = os.time()
	urlSuffix = "?id="..packageId.."&time="..time
	urlSuffix = LUtil.MakeB64SendData(urlSuffix)

	LxHttpHelper.DoWebRequestURL(true, urlList, urlSuffix, function (ret, result, url)
		if (ret ~= CS.YXWebRet.ok) then
			LogError("server list query result |" ..tostring(ret) .. " | " .. tostring(result))
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		LXFW.LxLog.WEB(result)

		if(result == "null") then
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		local resultTbl = JSON.decode(result)
		if(not resultTbl) then
			LogError("decode server json data error ... ")
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		if tostring(resultTbl.code) == "1" then
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		if(callFunc ~= nil) then callFunc(true, ret, resultTbl, url) end
	end,false)
end

function LServerUtil._QueryServerInfoFromWeb(callFunc, qType, gid, sid)
	local urlSuffix = ""
	local urlList = LGameSettings.platformUrlList

	--?platformkey=sample&time=1593855641&imei=aaa&sign=999

