	local sign = "999"

	qType = qType and qType or 1
	gid = gid and gid or 0
	sid = sid and sid or 0

	urlSuffix = "?id="..packageId.."&time="..time.."&imei="..imei.."&sign="..sign
	urlSuffix = urlSuffix.."&type="..qType
	urlSuffix = urlSuffix.."&gid="..gid
	urlSuffix = urlSuffix.."&sid="..sid

	urlSuffix = LUtil.MakeB64SendData(urlSuffix)

	--urlSuffix = "platformkey=ceshi&time=1112&imei=aaa&sign=999"
	--urlList = {"http://192.168.28.254:8081/data/api/getserverlist.do?"}

	LxHttpHelper.DoWebRequestURL(true, urlList, urlSuffix, function (ret, result, url)
		if (ret ~= CS.YXWebRet.ok) then
			LogError("server list query result |" ..tostring(ret) .. " | " .. tostring(result))
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		LXFW.LxLog.WEB(result)

		if(result == "null") then
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		local resultTbl = JSON.decode(result)
		if(not resultTbl) then
			LogError("decode server json data error ... ")
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		if tostring(resultTbl.code) == "1" then
			if(callFunc ~= nil) then callFunc(false, ret, result, url) end
			return
		end

		if(callFunc ~= nil) then callFunc(true, ret, resultTbl, url) end
	end)
end

function LServerUtil.DownFileMaskDataFromWeb(webUrl, ver, callFunc)
	if string.isempty(webUrl) then
		return 
	end
	
	local lngFlag = LPlayerPrefs.lngFlag
	if string.isempty(lngFlag) then
		lngFlag = "zhtw"
	end

	if '/' ~= string.sub(webUrl, string.len(webUrl)) then webUrl = webUrl .. '/' end

	--多语言版本的时候
	--local urlList = {webUrl..ver.."/"..lngFlag.."/".."keywordweb.json"}
	local urlList = {webUrl..ver.."/".."keywordweb.json"}

	LxHttpHelper.DoWebDownFile(urlList, function(url, ret, result, progress, bytes)
		if ret == CS.YXWebRet.ok then
			if(callFunc ~= nil) then callFunc(ret, result, url, bytes) end
		elseif ret == CS.YXWebRet.Loading then

		else
			LogError("mask data download | " .. tostring(ret) .. " | " ..tostring(result) .." | "..tostring(url))
			if(callFunc ~= nil) then callFunc(ret, result, url, bytes) end
		end
	end, false)
end


